UPDATE imported_students
SET gender = CASE
  WHEN student_id = ANY(ARRAY[
    3,4,7,13,15,16,18,19,24,25,26,27,29,37,38,39,41,43,45,48,49,50,53,55,59,60,61,64,
    70,71,73,74,78,79,82,84,85,86,87,90,91,92,96,97,98,99,101,103,104,112,114,115,
    116,117,119,120,122,125,127,130,131,133,134,135,142,143,146,148,149,150,154,158,
    159,160,162,165,166
  ]::int[]) THEN 'female'
  ELSE 'male'
END;

TRUNCATE TABLE
  discount_policy_students, fee_adjustments, fee_payments, student_attendance, student_class_history,
  student_fee_period_discounts, student_fee_period_items, student_fee_periods, student_service_subscriptions,
  student_service_usage_entries, students
RESTART IDENTITY CASCADE;

INSERT INTO classes (name, level, room, teacher_id)
SELECT class_name, MAX(class_level), '', NULL
FROM imported_students i
WHERE NOT EXISTS (SELECT 1 FROM classes c WHERE TRIM(c.name) = TRIM(i.class_name))
GROUP BY class_name;

WITH class_lookup AS (SELECT TRIM(name) AS class_name, MIN(id) AS class_id FROM classes GROUP BY TRIM(name))
INSERT INTO students (
  id, name, last_name, first_name, grade, email, date_of_birth, class_id, avatar, join_date, status, gender,
  phone, nationality, religion, province, ward, house_number, street, hamlet, birth_place,
  original_student_no, birth_address, birth_ward, birth_province, hometown_ward, hometown_province,
  birth_registration_ward, birth_registration_district, birth_registration_province,
  birth_registration_new_ward, birth_registration_new_province, student_id_issued_date,
  father_birth_year, mother_birth_year,
  father_name, father_birth_date, father_phone, father_email, father_login, father_id_number, father_id_issued_date, father_education, father_occupation,
  mother_name, mother_birth_date, mother_phone, mother_email, mother_login, mother_id_number, mother_id_issued_date, mother_education, mother_occupation,
  id_number, id_issued_place, id_issued_date, area, bhyt_number,
  household_house_number, household_street, household_ward, household_province, household_address,
  doc_household_registration, doc_parent_id, doc_birth_certificate, doc_student_id_form, doc_health_check, doc_residence_confirmation, doc_birth_certificate_copy,
  doc2_household_registration, doc2_parent_id, doc2_birth_certificate, doc2_student_id_form, doc2_health_check, doc2_residence_confirmation, doc2_birth_certificate_04,
  disability_type, policy_beneficiary, eye_disease, guardian_name, guardian_occupation, guardian_birth_year
)
SELECT
  i.student_id, i.name, i.last_name, i.first_name, i.grade, '', i.date_of_birth, c.class_id, '', i.join_date, i.status, i.gender,
  i.phone, i.nationality, i.religion, i.province, i.ward, i.house_number, i.street, i.hamlet, i.birth_place,
  i.original_student_no, i.birth_address, i.birth_ward, i.birth_province, i.hometown_ward, i.hometown_province,
  i.birth_registration_ward, i.birth_registration_district, i.birth_registration_province,
  i.birth_registration_new_ward, i.birth_registration_new_province, i.student_id_issued_date,
  i.father_birth_year, i.mother_birth_year,
  i.father_name, i.father_birth_date, i.father_phone, i.father_email, i.father_login, i.father_id_number, i.father_id_issued_date, i.father_education, i.father_occupation,
  i.mother_name, i.mother_birth_date, i.mother_phone, i.mother_email, i.mother_login, i.mother_id_number, i.mother_id_issued_date, i.mother_education, i.mother_occupation,
  i.id_number, i.id_issued_place, i.id_issued_date, i.area, i.bhyt_number,
  i.household_house_number, i.household_street, i.household_ward, i.household_province, i.household_address,
  i.doc_household_registration, i.doc_parent_id, i.doc_birth_certificate, i.doc_student_id_form, i.doc_health_check, i.doc_residence_confirmation, i.doc_birth_certificate_copy,
  i.doc2_household_registration, i.doc2_parent_id, i.doc2_birth_certificate, i.doc2_student_id_form, i.doc2_health_check, i.doc2_residence_confirmation, i.doc2_birth_certificate_04,
  '', '', '', '', '', ''
FROM imported_students i
LEFT JOIN class_lookup c ON c.class_name = TRIM(i.class_name)
ORDER BY i.student_id;

WITH class_lookup AS (SELECT TRIM(name) AS class_name, MIN(id) AS class_id FROM classes GROUP BY TRIM(name))
INSERT INTO student_class_history (student_id, from_class_id, to_class_id, effective_date, note)
SELECT i.student_id, NULL, c.class_id, COALESCE(i.join_date, CURRENT_DATE), 'Import data_hs.xlsx row ' || i.excel_row
FROM imported_students i
LEFT JOIN class_lookup c ON c.class_name = TRIM(i.class_name)
ORDER BY i.student_id;

SELECT setval(pg_get_serial_sequence('students', 'id'), COALESCE((SELECT MAX(id) FROM students), 1), (SELECT COUNT(*) > 0 FROM students));
SELECT setval(pg_get_serial_sequence('student_class_history', 'id'), COALESCE((SELECT MAX(id) FROM student_class_history), 1), (SELECT COUNT(*) > 0 FROM student_class_history));

COMMIT;
